import{_ as e,o,c as a,ag as r}from"./chunks/framework.BZohXCq9.js";const h=JSON.parse('{"title":"Spec / Command / Prompt","description":"","frontmatter":{},"headers":[],"relativePath":"reference/spec-command-prompt.md","filePath":"reference/spec-command-prompt.md"}'),d={name:"reference/spec-command-prompt.md"};function l(i,t,n,c,s,p){return o(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="spec-command-prompt" tabindex="-1">Spec / Command / Prompt <a class="header-anchor" href="#spec-command-prompt" aria-label="Permalink to &quot;Spec / Command / Prompt&quot;">​</a></h1><p>这三个概念经常被混淆，其实各管一摊。</p><h2 id="区别" tabindex="-1">区别 <a class="header-anchor" href="#区别" aria-label="Permalink to &quot;区别&quot;">​</a></h2><table tabindex="0"><thead><tr><th>概念</th><th>回答的问题</th><th>例子</th></tr></thead><tbody><tr><td><strong>Spec</strong></td><td>规则是什么？什么算合格？</td><td>笔记结构、审核标准、热点判断规则</td></tr><tr><td><strong>Command</strong></td><td>workflow 行为怎么执行？</td><td>先读什么、再写什么、最后输出什么</td></tr><tr><td><strong>Prompt</strong></td><td>agent 这个阶段产出什么？</td><td>brief 模板、fit-check 输出格式</td></tr></tbody></table><hr><h2 id="详细说明" tabindex="-1">详细说明 <a class="header-anchor" href="#详细说明" aria-label="Permalink to &quot;详细说明&quot;">​</a></h2><h3 id="spec-—-规则定义" tabindex="-1">Spec — 规则定义 <a class="header-anchor" href="#spec-—-规则定义" aria-label="Permalink to &quot;Spec — 规则定义&quot;">​</a></h3><p>回答：<strong>什么算合格？</strong></p><ul><li>一篇笔记合格长什么样 → <code>note.spec.md</code></li><li>review 看哪些维度 → <code>review.spec.md</code></li><li>trend fit 判断什么 → <code>trend.spec.md</code></li><li>publish 包必须包含什么 → <code>publish.spec.md</code></li></ul><h3 id="command-—-行为约定" tabindex="-1">Command — 行为约定 <a class="header-anchor" href="#command-—-行为约定" aria-label="Permalink to &quot;Command — 行为约定&quot;">​</a></h3><p>回答：<strong>这个 workflow 怎么执行？</strong></p><ul><li><code>/xhs:quick</code> 先读 spec、再写 brief、最后产 draft</li><li><code>/xhs:publish</code> 先生成终稿、再打包封面素材</li></ul><p>它定义的是<strong>步骤顺序和职责</strong>，不关心具体输出格式。</p><h3 id="prompt-—-输出协议" tabindex="-1">Prompt — 输出协议 <a class="header-anchor" href="#prompt-—-输出协议" aria-label="Permalink to &quot;Prompt — 输出协议&quot;">​</a></h3><p>回答：<strong>agent 应该输出成什么样？</strong></p><ul><li>quick brief 应该补哪些字段</li><li>trend fit-check 结论怎么写</li><li>publish 包各文件什么格式</li></ul><p>它定义的是<strong>产出物的结构</strong>，确保 AI 输出可预期。</p><hr><h2 id="一句话总结" tabindex="-1">一句话总结 <a class="header-anchor" href="#一句话总结" aria-label="Permalink to &quot;一句话总结&quot;">​</a></h2><ul><li><strong>Spec</strong> — 规则（什么算合格）</li><li><strong>Command</strong> — 步骤（怎么做这个 workflow）</li><li><strong>Prompt</strong> — 格式（这一阶段产出什么）</li></ul><hr><h2 id="在系统中的位置" tabindex="-1">在系统中的位置 <a class="header-anchor" href="#在系统中的位置" aria-label="Permalink to &quot;在系统中的位置&quot;">​</a></h2><p>不是摆设，已经进入系统层：</p><ul><li><code>init</code> 安装这些文件到 <code>.xhsops/</code></li><li><code>validate</code> / <code>doctor</code> 检查它们是否存在</li><li>AI 执行 slash command 时自动读取</li></ul>',24)])])}const u=e(d,[["render",l]]);export{h as __pageData,u as default};
